import{_ as o,o as t,c as n,a0 as i}from"./chunks/framework.CED9SG98.js";const g=JSON.parse('{"title":"DIKW 模型","description":"Data-Information-Knowledge-Wisdom 金字塔，知识内化的底层规律，AI 知识库设计的关键框架","frontmatter":{"type":"Concept","title":"DIKW 模型","description":"Data-Information-Knowledge-Wisdom 金字塔，知识内化的底层规律，AI 知识库设计的关键框架","source_platform":"内部","ingest_date":"2026-07-12T00:00:00.000Z","access_date":"2026-07-12T00:00:00.000Z","tags":["知识管理","认知科学","PKMS","AI边界"],"status":"compiled","review_count":0,"last_review":"2026-07-12T00:00:00.000Z","next_review":"2026-07-13T00:00:00.000Z"},"headers":[],"relativePath":"wiki/concepts/DIKW.md","filePath":"wiki/concepts/DIKW.md"}'),l={name:"wiki/concepts/DIKW.md"};function s(e,a,r,d,h,c){return t(),n("div",null,[...a[0]||(a[0]=[i(`<h1 id="dikw-模型" tabindex="-1">DIKW 模型 <a class="header-anchor" href="#dikw-模型" aria-label="Permalink to &quot;DIKW 模型&quot;">​</a></h1><blockquote><p>Data → Information → Knowledge → Wisdom</p></blockquote><p>知识管理的经典金字塔模型，揭示了人类内化信息的底层规律。</p><h2 id="四级跃迁" tabindex="-1">四级跃迁 <a class="header-anchor" href="#四级跃迁" aria-label="Permalink to &quot;四级跃迁&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>手中数据 (Data)</span></span>
<span class="line"><span>    ↓ 主动解读</span></span>
<span class="line"><span>眼中信息 (Information)</span></span>
<span class="line"><span>    ↓ 主动思考</span></span>
<span class="line"><span>脑中知识 (Knowledge)</span></span>
<span class="line"><span>    ↓ 主动实践</span></span>
<span class="line"><span>口中智慧 (Wisdom)</span></span></code></pre></div><h3 id="数据-data" tabindex="-1">数据 (Data) <a class="header-anchor" href="#数据-data" aria-label="Permalink to &quot;数据 (Data)&quot;">​</a></h3><ul><li><strong>定义</strong>: 原始、未加工的事实和信号</li><li><strong>示例</strong>: 一段代码、一张截图、一个数字</li><li><strong>AI 的作用</strong>: 收集、存储、格式化</li></ul><h3 id="信息-information" tabindex="-1">信息 (Information) <a class="header-anchor" href="#信息-information" aria-label="Permalink to &quot;信息 (Information)&quot;">​</a></h3><ul><li><strong>定义</strong>: 有组织、有上下文的数据</li><li><strong>跃迁条件</strong>: 人的<strong>主动解读</strong></li><li><strong>示例</strong>: &quot;这个数据意味着用户留存率下降了 5%&quot;</li><li><strong>AI 的作用</strong>: 摘要、分类、关联</li></ul><h3 id="知识-knowledge" tabindex="-1">知识 (Knowledge) <a class="header-anchor" href="#知识-knowledge" aria-label="Permalink to &quot;知识 (Knowledge)&quot;">​</a></h3><ul><li><strong>定义</strong>: 能指导行动的信息</li><li><strong>跃迁条件</strong>: 人的<strong>主动思考</strong></li><li><strong>示例</strong>: &quot;留存率下降可能是因为新版本的 onboarding 流程有问题，我需要去验证&quot;</li><li><strong>AI 的作用</strong>: 对比、查漏、模拟</li></ul><h3 id="智慧-wisdom" tabindex="-1">智慧 (Wisdom) <a class="header-anchor" href="#智慧-wisdom" aria-label="Permalink to &quot;智慧 (Wisdom)&quot;">​</a></h3><ul><li><strong>定义</strong>: 跨情境的判断力和直觉</li><li><strong>跃迁条件</strong>: 人的<strong>主动实践</strong> + 反思</li><li><strong>示例</strong>: &quot;每次做 onboarding 改动都要留 A/B 测试窗口，这是我过去三次教训总结出来的&quot;</li><li><strong>AI 的作用</strong>: <strong>无法替代</strong></li></ul><h2 id="对-pkms-的启示" tabindex="-1">对 PKMS 的启示 <a class="header-anchor" href="#对-pkms-的启示" aria-label="Permalink to &quot;对 PKMS 的启示&quot;">​</a></h2><h3 id="ai-的正确位置-体力活" tabindex="-1">AI 的正确位置（体力活） <a class="header-anchor" href="#ai-的正确位置-体力活" aria-label="Permalink to &quot;AI 的正确位置（体力活）&quot;">​</a></h3><ul><li>数据层: 收集、OCR、归档</li><li>信息层: 摘要、提取、分类</li><li>知识层: 对比、关联、模拟</li></ul><h3 id="人的主权-不可替代" tabindex="-1">人的主权（不可替代） <a class="header-anchor" href="#人的主权-不可替代" aria-label="Permalink to &quot;人的主权（不可替代）&quot;">​</a></h3><ul><li><strong>判断</strong>: 什么值得知道</li><li><strong>思考</strong>: 为什么关心、跟什么关联</li><li><strong>实践</strong>: 下一步做什么</li><li><strong>反思</strong>: 经验提炼为智慧</li></ul><h2 id="常见误区" tabindex="-1">常见误区 <a class="header-anchor" href="#常见误区" aria-label="Permalink to &quot;常见误区&quot;">​</a></h2><h3 id="ai-幻觉-陷阱" tabindex="-1">&quot;AI 幻觉&quot;陷阱 <a class="header-anchor" href="#ai-幻觉-陷阱" aria-label="Permalink to &quot;&quot;AI 幻觉&quot;陷阱&quot;">​</a></h3><blockquote><p>&quot;AI 帮你把一楼装修得极度漂亮，但你站在一楼惊叹&#39;我住到顶楼了&#39;。&quot;</p></blockquote><ul><li>一键总结 ≠ 理解</li><li>完整知识图谱 ≠ 掌握</li><li>精美目录结构 ≠ 认知跃迁</li></ul><h3 id="收藏癖-2-0" tabindex="-1">收藏癖 2.0 <a class="header-anchor" href="#收藏癖-2-0" aria-label="Permalink to &quot;收藏癖 2.0&quot;">​</a></h3><p>AI 消灭了收藏的最后一点摩擦力，让人误以为&quot;收集=学习&quot;。</p><h2 id="最小行动-思考三问法" tabindex="-1">最小行动（思考三问法） <a class="header-anchor" href="#最小行动-思考三问法" aria-label="Permalink to &quot;最小行动（思考三问法）&quot;">​</a></h2><ol><li><strong>哪句话击中了我？</strong> → 感受取舍</li><li><strong>为什么触动？</strong> → 深度加工，联系经历</li><li><strong>接下来 2 分钟做什么？</strong> → 行动落地</li></ol><h2 id="关联" tabindex="-1">关联 <a class="header-anchor" href="#关联" aria-label="Permalink to &quot;关联&quot;">​</a></h2><ul><li>[[sources/2026-07-12-karpathy-zhishiku-huiche]] — Andrew 的深度反思</li><li>[[concepts/PKMS]] — 本系统的设计理念</li><li>[[concepts/AI-Assisted-Thinking]] — AI 辅助思考的边界</li></ul>`,28)])])}const p=o(l,[["render",s]]);export{g as __pageData,p as default};
